SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpb_kep_get_keepitem_name ( as_keeping_item char ,as_type_money char ,as_coll char ) RETURNS varchar AS $body$
DECLARE

ls_keep_type_code   sc_kep_return_piority.keep_type%type;
ls_coll  sc_kep_return_piority.loan_type%type;
ls_type_money   sc_kep_return_piority.type_money%type;
ls_name varchar(200);
ls_type varchar(50);
--ls_ruletype varchar2(2);
ls_ruletype sc_lon_m_rule.loan_type%type;


BEGIN

   ls_keep_type_code := trim(both as_keeping_item );
  ls_coll := trim(both as_coll );
  ls_type_money := trim(both as_type_money );

  case substr( ls_keep_type_code ,1,2)
        when 'ML' then   -- เงินกู้
          if ls_coll = 'CO' then
              ls_ruletype := substr( ls_keep_type_code ,3,2);
             
              begin
                select loan_type into STRICT ls_ruletype
                from sc_lon_m_rule
                where priority_keep_coll = ls_ruletype  LIMIT 1;
                exception 
                when no_data_found then ls_ruletype := '';
                when others then CALL spa_dberror('E27 : FPB_KEP_GET_KEEPITEM_NAME');
              end;
          else
            ls_ruletype := substr( ls_keep_type_code ,3,2);
          end if;

          begin
            select loan_type_description into STRICT ls_name
            from sc_lon_m_rule
            where loan_type = ls_ruletype;
            exception
            when no_data_found then ls_name := '';
            when others then CALL spa_dberror('E39 : FPB_KEP_GET_KEEPITEM_NAME');
          end;

          if coalesce(ls_name::text, '') = '' or len(ls_name) = 0 then
            ls_name	:= '<ไม่มีข้อมูล>';
          else
            ls_name	:= ls_ruletype || ' ' || ls_name;
            ls_ruletype	:= '';
          end if;

        when 'MD' then  -- เงินฝากรายเดือน
          ls_ruletype := substr( ls_keep_type_code ,3,2);
          
           begin
            select deposit_name into STRICT ls_name
            from sc_dep_m_rule
            where deposit_type_code = ls_ruletype;
            exception
            when no_data_found then ls_name := '';
            when others then CALL spa_dberror('E58 : FPB_KEP_GET_KEEPITEM_NAME');
          end;

          if coalesce(ls_name::text, '') = '' or len(ls_name) = 0 then
            ls_name	:= '<ไม่มีข้อมูล>';
          else
            ls_name		:= ls_ruletype || ' ' || ls_name;
            ls_ruletype	:= '';
          end if;

        else
          ls_name		:= '';
          begin
            select trim(both keeping_type_name ) into STRICT ls_name
            from sc_kep_m_ucf_keeping_item_type
            where keeping_type_code = ls_keep_type_code;
            exception
            when no_data_found then ls_name := '';
            when others then CALL spa_dberror('E76 : FPB_KEP_GET_KEEPITEM_NAME');
          end;

          if coalesce(ls_name::text, '') = '' or len(ls_name) = 0 then
            ls_name	:= '<ไม่มีข้อมูล>';
          end if;

      end case;

      if substr( ls_keep_type_code ,1,2) = 'ML' then
        case ls_type_money
          when 'P' then
            ls_type	:= 'เงินต้น';
          when 'I' then
            ls_type	:= 'ดอกเบี้ย';
          when 'A' then
            ls_type	:= 'ดอกเบี้ยค้าง';
          when 'T' then
            ls_type	:= 'ดอกเบี้ยปัจจุบัน';
          else
            ls_type	:= '<ไม่มีข้อมูล>';
        end case;

        ls_name	:=  ( ls_type || '  ' || ls_ruletype )  || ' ' || ls_name;
      else
        ls_name	:=  ( ls_ruletype ) || ' ' || ls_name;
      end if;

  RETURN ls_name;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
